// PR 3 — closes MW-FE-008 (DPO email in bundle).
// DPO_EMAIL is NO LONGER bundled. Use getDpoContactUrl() instead —
// resolved at runtime via /api/legal/dpo-contact endpoint (CSP-allowed
// same-origin only). The endpoint is owned by the backend so it can
// rotate the underlying contact (form URL, alias, etc.) without rebuilding.
export function getDpoContactUrl(): string {
  // Same-origin endpoint — served by Astro backend, returns the current
  // DPO contact URL (rotated in env, never bundled).
  return "/api/legal/dpo-contact";
}

